#include <stdio.h>

int waysToClimb(int n) {
    if (n == 1) return 1;
    if (n == 2) return 2;
    int a = 1, b = 2, c;
    for (int i = 3; i <= n; ++i) {
        c = a + b;
        a = b;
        b = c;
    }
    return b;
}

int main() {
    int T, n;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &n) != 1) break;
        printf("%d\n", waysToClimb(n));
    }
    return 0;
}

